import{f as a,o as d,c as r,a2 as e}from"./chunks/framework.DHYrF-q6.js";const f=JSON.parse('{"title":"学习导航","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1780927175000}'),o={name:"guide/index.md"};function i(n,t,l,s,c,p){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="学习导航" tabindex="-1">学习导航 <a class="header-anchor" href="#学习导航" aria-label="Permalink to &quot;学习导航&quot;">​</a></h1><p>欢迎来到高级工程师 / AI 应用工程师面试准备 Wiki！</p><h2 id="这个-wiki-是什么" tabindex="-1">这个 Wiki 是什么？ <a class="header-anchor" href="#这个-wiki-是什么" aria-label="Permalink to &quot;这个 Wiki 是什么？&quot;">​</a></h2><p>这是一个<strong>系统化、可执行</strong>的面试准备知识库，帮助你在 <strong>3-4 个月内</strong>从 Java 中级水平提升到高级工程师 / AI 应用工程师面试水平。</p><h2 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用？&quot;">​</a></h2><h3 id="_1-先看全局" tabindex="-1">1. 先看全局 <a class="header-anchor" href="#_1-先看全局" aria-label="Permalink to &quot;1. 先看全局&quot;">​</a></h3><ul><li><a href="./roadmap"><strong>知识图谱</strong></a> — 看完整知识全貌，了解各个模块之间的关系</li><li><a href="./plan"><strong>16周学习计划</strong></a> — 按周拆解的可执行计划，每天学什么一目了然</li></ul><h3 id="_2-按模块逐项击破" tabindex="-1">2. 按模块逐项击破 <a class="header-anchor" href="#_2-按模块逐项击破" aria-label="Permalink to &quot;2. 按模块逐项击破&quot;">​</a></h3><p>每个模块都有独立的文档树，包含「核心原理 → 面试考点 → 实战练习」三个层次：</p><table tabindex="0"><thead><tr><th>模块</th><th>重点</th><th>预计时长</th></tr></thead><tbody><tr><td><a href="/portal/java-advanced/">Java 高级</a></td><td>JVM、并发、集合源码、设计模式</td><td>4 周</td></tr><tr><td><a href="/portal/spring-ecosystem/">Spring 生态</a></td><td>Spring Boot 原理、Spring Cloud 微服务</td><td>2 周</td></tr><tr><td><a href="/portal/database/">数据库</a></td><td>MySQL 优化、Redis 深度</td><td>3 周</td></tr><tr><td><a href="/portal/middleware/">中间件</a></td><td>消息队列、分布式理论</td><td>2 周</td></tr><tr><td><a href="/portal/computer-network/">计算机网络</a></td><td>TCP/IP、HTTP、HTTPS、DNS、IO 多路复用</td><td>1-2 周</td></tr><tr><td><a href="/portal/operating-system/">操作系统</a></td><td>进程线程、虚拟内存、IO 模型、调度</td><td>1-2 周</td></tr><tr><td><a href="/portal/high-concurrency/">高并发架构</a></td><td>限流熔断、系统设计</td><td>3 周</td></tr><tr><td><a href="/portal/security/">安全</a></td><td>密码学、认证授权、OWASP、零信任</td><td>1 周</td></tr><tr><td><a href="/portal/software-testing/">软件测试</a></td><td>测试金字塔、JUnit/Mockito、TDD、契约测试</td><td>1 周</td></tr><tr><td><a href="/portal/software-engineering/">软件工程</a></td><td>SOLID原则、重构、Code Review、敏捷开发</td><td>1 周</td></tr><tr><td><a href="/portal/ai-application/">AI 应用</a></td><td>RAG、Agent、LangChain</td><td>2 周</td></tr><tr><td><a href="/portal/frontend/">前端</a></td><td>Vue/React 框架、工程化、浏览器原理、性能优化、面试题</td><td>2-3 周</td></tr><tr><td><a href="/portal/devops/">DevOps</a></td><td>Linux、Docker、K8s、CI/CD</td><td>1-2 周</td></tr><tr><td><a href="/portal/big-data/">大数据</a></td><td>Hadoop/Spark/Flink 核心原理</td><td>0.5-1 周</td></tr><tr><td><a href="/portal/tech-management/">技术管理</a></td><td>技术方案设计、团队管理</td><td>0.5 周</td></tr><tr><td><a href="/portal/interview/">面试冲刺</a></td><td>算法、系统设计面试、行为面试</td><td>最后 2 周</td></tr></tbody></table><h3 id="_3-配合-code-projects-实战" tabindex="-1">3. 配合 code-projects 实战 <a class="header-anchor" href="#_3-配合-code-projects-实战" aria-label="Permalink to &quot;3. 配合 code-projects 实战&quot;">​</a></h3><p>每个模块学习后，在 <code>code-projects</code> 目录找到对应的代码示例和实战项目，<strong>动手写代码比单纯看文档效率高 5 倍</strong>。</p><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">费曼学习法</p><p>学完一个知识点后，试着用自己的话向别人讲一遍。讲不清楚的地方，就是你没理解透的地方。</p></div><div class="warning custom-block"><p class="custom-block-title">不要贪多</p><p>3-4 个月时间有限，重点是<strong>面试高频考点 + 核心原理</strong>，而不是面面俱到。每个模块都有标注 ⭐ 的重点内容，优先掌握。</p></div><div class="info custom-block"><p class="custom-block-title">输出倒逼输入</p><p>每学完一个模块，在 Wiki 中补充自己的笔记和理解。这个 Wiki 不仅是你复习的资料，也是你学习的产出。</p></div>',16)])])}const u=a(o,[["render",i]]);export{f as __pageData,u as default};
